var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"중계소 상태는 어떤가?","JPN":"中継所の状態はどうだ？","ENG":"How's the relay station?","TWN":"基地台情況如何？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"안 좋습니다. 건물 안이 완전히 쑥대밭이 됐어요.","JPN":"良くありません。建物の中が完全に荒らされています。","ENG":"Not good. The inside of the building is completely in ruins.","TWN":"不太好，裡面根本就是一團混亂。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"느낌이 안 좋군. 침식체들이 할 만한 짓은 아니야.","JPN":"嫌な予感がするな。侵食体の仕業ではなさそうだ。","ENG":"I've got a bad feeling about this. This isn't something C.O.s would do.","TWN":"我有不好的預感，這不像是侵蝕體會做的事。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"하지만 이대로 두면 다른 주민들은 갱단한테 시달려도 도와달라고 할 방법이 없으니까요.","JPN":"でも、このままにしておくと住民たちがギャングにやられた時に助けを求める手段がなくなります。","ENG":"But if we don't fix it, the community will have no way of reaching out for help when the gangs harass them.","TWN":"但是不修的話，居民被幫派找麻煩時，會沒有求救的管道。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 주위에 수상한 움직임은 없는지 경계하고 있도록.","JPN":"そうだな。周りに怪しい動きはないか警戒してくれ。","ENG":"I know. Just keep an eye out for anything suspicious.","TWN":"也是，要注意一下周圍有沒有可疑的行動。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"두목이 부상을 입고 도망쳤다고 해도, 예언회가 완전히 와해된 건 아냐.","JPN":"ボスが負傷して逃げたとしても、預言会が完全に解散したわけではない。","ENG":"Their boss may be away licking his wounds, but that doesn't mean the MPS has been completely destroyed.","TWN":"雖然領頭的負傷逃跑，但預言會並沒有完全瓦解。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"트렁크에 있는 공구 챙겨서 따라와, 호라이즌.","JPN":"トランクにある工具を持ってついて来てくれ、ホライズン。","ENG":"Grab the tools from the trunk and follow me, Horizon.","TWN":"地平線，把箱子裡的工具拿來。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……알겠습니다. 휴먼.","JPN":"……わかりました、ヒューマン。","ENG":"…Very well, human.","TWN":"……好的，人類"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"팔자에도 없는 기술자 노릇까지 하게 만드는군. 참 성가신 동네야.","JPN":"専門でもないエンジニアの仕事までさせられることになるとは。本当に手のかかる町だ。","ENG":"Hmph, I can't believe they got me playing cable guy over here. What a lousy neighborhood.","TWN":"竟然還害我當起維修工，真是個麻煩的地方。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그렇게 생각하지 않나, 호라이즌?","JPN":"そう思わないか、ホライズン？","ENG":"Wouldn't you agree, Horizon?","TWN":"地平線，你不覺得嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼이 당신의 번식 욕구를 자극하는 행동을 했습니까.","JPN":"レイチェルがあなたの繁殖欲求を刺激するような行動をしましたか？","ENG":"Has Rachel stimulated your impulse for propagation?","TWN":"瑞秋有做什麼刺激你繁殖慾望的行為嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"조카뻘인 여자애한테 치근덕거리는 취미는 없어. 헛소리 말고 거기 드라이버나 집어 줘.","JPN":"姪っ子に当たる歳の女の子に手を出す趣味はない。くだらない質問はやめて、そこのドライバーでも渡してくれ。","ENG":"Don't be gross. She's young enough to be my niece. Shut up and just grab me that screwdriver.","TWN":"瑞秋就跟我的姪女一樣，我沒有戀童癖好嗎。少胡說八道，把螺絲起子拿給我。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여기 있습니다. 그럼 어째서 그녀의 불합리한 요구를 받아들인 겁니까?","JPN":"はい、どうぞ。ならばどうして彼女の不合理な要求を受け入れたのですか？","ENG":"Here it is. Then why did you agree to her unreasonable request?","TWN":"給你。那你爲什麼要接受她不合理的要求？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네가 눈에 밟혔다고 하면 되나?","JPN":"あんたのことが目に浮かんだというか、まあそんな感じだ。","ENG":"I guess you got my attention.","TWN":"是因為你的關係，這樣可以嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"딱히 당신 시선을 끌 목적은 없습니다만.","JPN":"別にあなたの目を引くような行動をした覚えはありませんが。","ENG":"But I have no reason to attract your attention.","TWN":"我沒有想要吸引你目光的意思。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"남들 관심 받기 싫었으면 애초에 그렇게 온몸으로 나 좀 챙겨 달라고 하지 말았어야지.","JPN":"人の目を引きたくなければ、かまってほしいと思われるような行動をしなければいいだろ？","ENG":"If you really wanted folks to leave you alone, you shouldn't have made it so obvious that you wanted attention.","TWN":"如果不希望別人關心你，那一開始就不要表現得一副很需要人家照顧的樣子。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이해할 수 없는 관점이군요. 저는 정서적인 공감대를 요구한 적 없습니다.","JPN":"理解できない観点ですね。情緒的共感を求めた覚えはありませんが。","ENG":"That does not compute. I've never demanded emotional sympathy from anyone.","TWN":"我無法理解，我從來沒有要求過情感上的交流。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아니, 너는 항상 그러고 있었어. 복수를 작정한 녀석들한테서 으레 보이는 모습이지.","JPN":"いや、あんたはいつもそう見えたよ。本来なら復讐を決意した人がそんな風に見えるはずだがな。","ENG":"I beg to differ. You've been craving for attention this whole time. It's a common trait among those who seek revenge.","TWN":"不，你一直都是這樣。在那些想報仇的人面前，一副楚楚可憐的樣子。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그걸 레이첼이 제일 먼저 알아챘을 뿐이고. 인두기 좀 손에 쥐어 주겠나?","JPN":"それに一番はやく気づいたのがレイチェルだったってわけだ。半田ごてを渡してくれないか？","ENG":"Rachel just happened to take notice before anyone else. Pass me the soldering iron, will you?","TWN":"只是是瑞秋最先發現到的。那個烙鐵給我一下。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여기 있습니다. 그리고 저에게 복수처럼 감정적인 판단은 어울리지 않습니다.","JPN":"はい、どうぞ。そして私に、復讐のような感情的判断は似合いません。","ENG":"Here it is. For the record, an emotional endeavor such as revenge does not suit me.","TWN":"給你。另外，報仇這種情緒性的字眼，不適合用在我身上。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"상대에게서 받아내야 할 것을 받아낸다. 그것뿐입니다.","JPN":"相手からもらうべきものをもらう。それだけです。","ENG":"I'm simply taking what is owed me. That is all.","TWN":"我只是從對方身上取回我該取回的東西，如此而已。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너무 경계하지 마. 이 분야 선배로서 충고 몇 마디 해 주려는 거다.","JPN":"あまり警戒するな。この分野の先輩としてアドバイスしているだけだ。","ENG":"No need to get all defensive. I'm just trying to give you a bit of advice as someone with experience in this field.","TWN":"不要緊張，我只是作為報仇界的前輩，給你一些忠告而已。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"복수를 작정했다면…… 네가 지금 가진 걸 미련없이 버릴 각오도 해 둬.","JPN":"とにかく復讐を決意したなら……あんたが今持っているものを躊躇せず捨てる覚悟もしておけ。","ENG":"If you've made up your mind to take revenge… you'd better be ready to forfeit everything else in your life.","TWN":"一旦決定要報仇……那你現在擁有的東西，都必須毫無眷戀地捨棄。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 행동 알고리즘에 너무 낭만적으로 접근하셨군요.","JPN":"私の行動アルゴリズムに対して、あまりにもロマンチックな捉え方ですね。","ENG":"You've approached my behavior algorithm with undue romanticism.","TWN":"我的行為演算法沒有你想的那麼浪漫。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼이나 이 지역의 빈민들이 서로 상처를 핥아 주며 부대끼는 생활을 <color=#ffd34c>제가 가진 것</color>이라고 생각했다면, 틀렸습니다.","JPN":"レイチェルやこの地域の貧民たちがお互いに傷をなめ合いながら生きる生活を<color=#ffd34c>私が持っているもの</color>だと思っているなら、それは違います。","ENG":"If you think living all huddled together and licking each other's wounds like Rachel and the rest of the impoverished members of this community is <color=#ffd34c>part of my life</color>, you're wrong.","TWN":"你以為瑞秋，或是這個地方的貧民互舔傷口依偎的生活，<color=#ffd34c>就是我擁有的東西</color>嗎？那可就大錯特錯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"강한 부정은 강한 긍정이라던데…….","JPN":"強い否定は強い肯定だそうだが……","ENG":"Hmm, such a long-winded denial seems suspect, if you ask me…","TWN":"我聽說……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그렇다면 상대한테서 뭘 받아내고 싶지?","JPN":"それで、相手から何をもらいたいんだ？","ENG":"Fine, then. What's this stuff you want to take back so much?","TWN":"那你想從對方取回什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"돈. 당신들이 만들고 당신들이 매달리는 그 돈입니다.","JPN":"「お金」。あなたたちが作り、そしてあなたたちがしがみつく、その「お金」です。","ENG":"Money, of course. The instrument you humans obsess over so desperately.","TWN":"錢。就是你們自己創造，自己又身陷其中的 錢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들은 돈에 엮이면 저열한 본성을 드러내죠. 그 순간의 추태를 관찰하는 것이 제 낙입니다.","JPN":"ヒューマンたちはお金が絡むと下劣な本性を見せます。その瞬間の醜態を観察することが私の楽しみです。","ENG":"Humans reveal their basest instincts when it comes to money. Observing this ugly monstrosity of your kind is my favorite pastime.","TWN":"人類一旦財迷心竅，就會暴露出醜陋的本性。而我的興趣，就是觀察那瞬間的醜陋。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"멀쩡하게 생겨선 꽤 음습한 취미를 가지고 계셨군. 사채업자 나리.","JPN":"見た目は普通なのにかなりイヤらしい趣味をお持ちで。闇金業者様。","ENG":"You've got a pretty dark hobby for someone who looks so harmless. Loan shark lady.","TWN":"高利貸大人長得人模人樣的，沒想到興趣這麼黑暗。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그럼 돈놀이나 계속하지, 뭐하러 푼돈 벌자고 이런 폐허까지 따라나왔나?","JPN":"じゃあ、そのお金で人間をもてあそぶ仕事を続ければいいのに、何のために小遣い程度しか稼げないこんな廃墟までついて来たんだ？","ENG":"Then why didn't you stick to the money-lending business? There's hardly a penny you can squeeze out of this dump.","TWN":"那你為什麼不繼續玩金錢遊戲，還來這個廢墟賺那幾毛錢幹嘛？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"교관님, 안에 계십니까?","JPN":"教官、中にいますか？","ENG":"Are you in there, Instructor?","TWN":"教官，你在裡面嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하아……. 질리지도 않고 교관 타령이군.","JPN":"はぁ……またその呼び方か。","ENG":"Ugh… When will they drop this Instructor nonsense?","TWN":"哀……煩不煩啊，教官長教官短的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"바쁘신데 죄송합니다. C조 친구가 바로 옆 폐건물에서 이런 걸 발견했습니다.","JPN":"お忙しいところ申し訳ありません。C組がすぐ隣の廃墟ビルでこんな物を見つけました。","ENG":"Sorry to interrupt, but a fella in Charlie Squad found this in the abandoned building next door.","TWN":"不好意思打擾，C組的人說在旁邊的廢棄建築裡發現這個東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"무슨 신호기 같아 보이는데, 교관님이라면 혹시 아실까 해서요.","JPN":"何かの発信機のように見えますが、教官ならご存知かと思いまして。","ENG":"It looks like some sort of a transponder… but I figured you might recognize it.","TWN":"看起來有點像信號器，我想說教官你可能會知道。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"잠깐, 이건…….","JPN":"おい、これは……","ENG":"Hang on, isn't this…","TWN":"我看看，這……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"빌어먹을, 이터니움 공명파 발생기잖아.","JPN":"くそっ、エタニウム共鳴波発生器じゃないか。","ENG":"Damn it, it's an Eternium Resonance Pulse Generator.","TWN":"該死，這不是永恆之金共鳴裝置嗎！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"침식체를 유인할 수 있다는 신호기 말입니까?","JPN":"侵食体を誘引できるという発信機のことですか？","ENG":"You mean a transponder, capable of luring Corrupted Objects?","TWN":"是可以引來侵蝕體的信號嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 요즘 태스크포스 용병 놈들이 경쟁자를 묻어 버리는 데 요긴하게 쓴다지.","JPN":"そうだ。最近タスクフォースカンパニーの傭兵たちがライバルを排除する時に使っているらしい。","ENG":"That's right. I hear it comes in handy for TASKFORCE mercenaries looking to take out their competitors.","TWN":"沒錯。最近特遣勢力的傭兵們常拿來弄競爭對手。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……설치 예상 시각과 신호기의 출력을 계산했을 때, 이 근방 침식체가 전부 몰려오기까지 1분 13초 남았습니다.","JPN":"……設置予想時刻と発信機の出力を計算したところ、周辺の侵食体が押し寄せてくるまで残り1分13秒です。","ENG":"…Based on the calculations of the estimated activation time and the transponder's output levels, we have 1 minute 13 seconds until all the C.O.s in the vicinity swarm this location.","TWN":"……計算安裝預計時間和信號器的功率，距離附近的侵蝕體全部聚集到這裡，還剩下1分13秒。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너그러운 카운트다운이군. 행운의 여신이 미소를 덤핑해 주셨나.","JPN":"寛大なカウントダウンだな。幸運の女神のご加護か。","ENG":"Well, that's plenty of time. Lady Luck must be in an extra good mood today.","TWN":"時間還真充裕呢！是幸運女神眷顧我們嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"다들 장비 챙겨!","JPN":"全員、装備を持て！","ENG":"Everyone, grab your gear!","TWN":"大家拿起裝備！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"침식체들이 더 몰려들기 전에 여기를 벗어나야 한다!","JPN":"侵食体が押し寄せてくる前にここから抜け出す！","ENG":"We've got to get out of here before the C.O.s arrive!","TWN":"必須趁侵蝕體還沒聚集到這裡之前，趕緊離開！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"주, 주교님! 놈들이 움직입니다! 우리 계획을 눈치 챈 모양입니다!","JPN":"し、司教様！　奴らが動き出しました！　我々の計画に気づいたようです！","ENG":"B-Bishop! They're on the move! They must have caught on to our plot!","TWN":"主教！那些傢伙有動靜！可能是察覺到我們的計劃！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"쳇…… 제프티 놈들, 하필이면 저딴 구형 신호기를 넘기다니.","JPN":"ちっ……ジェフティの奴ら、よりによってあんな旧型発信機をよこしやがって。","ENG":"Damn those crooks at Jehuty… giving us an obsolete model like that.","TWN":"可惡……傑夫堤那些傢伙，竟然給我們舊款的信號器！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"저들을 쫓아라! 형제들이여!","JPN":"やつらを追え！　兄弟よ！","ENG":"Pursue them, brethren!","TWN":"弟兄們，給我追！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"예언회에 대적한 대가가 무엇인지 똑똑히 알려 줘라!","JPN":"預言会に歯向かうとどうなるのか、思い知らせてやれ！","ENG":"Show them the price of crossing the Society!","TWN":"要讓他們清楚知道，和預言會作對的下場是什麼！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};